// ── BrandFlow: Build Search Query ────────────────────────────────────────
// Rotates through keyword sets aligned with Brandflow's offerings.
// Each week a different theme is searched so the Insight section covers
// a broad range of topics over time.

const KEYWORD_SETS = [
  {
    query: 'business process automation South Africa SME',
    category: 'Getting Started',
    tags: ['automation', 'SME', 'South Africa', 'productivity']
  },
  {
    query: 'n8n workflow automation small business South Africa',
    category: 'Tools',
    tags: ['n8n', 'workflow', 'automation', 'South Africa']
  },
  {
    query: 'POPIA compliance automation South Africa 2026',
    category: 'Compliance',
    tags: ['POPIA', 'compliance', 'data protection', 'South Africa']
  },
  {
    query: 'automation ROI cost savings South Africa business',
    category: 'Getting Started',
    tags: ['ROI', 'cost savings', 'automation', 'South Africa']
  },
  {
    query: 'AI machine learning business automation South Africa',
    category: 'Tools',
    tags: ['AI', 'machine learning', 'automation', 'South Africa']
  },
  {
    query: 'invoice payment workflow automation South Africa SME',
    category: 'Case Study',
    tags: ['finance', 'invoicing', 'automation', 'South Africa']
  },
  {
    query: 'API integration business automation South Africa',
    category: 'Tools',
    tags: ['API', 'integration', 'automation', 'South Africa']
  },
  {
    query: 'workflow automation small business case study South Africa',
    category: 'Case Study',
    tags: ['case study', 'workflow', 'automation', 'South Africa']
  }
];

// Pick this week's keyword set (cycles every 8 weeks)
const weekIndex = Math.floor(Date.now() / (7 * 24 * 60 * 60 * 1000));
const keywordSet = KEYWORD_SETS[weekIndex % KEYWORD_SETS.length];

// Pass through base articles from cPanel for deduplication
const fetchResponse = $input.first().json;
const baseArticles = Array.isArray(fetchResponse.articles) ? fetchResponse.articles : [];

return [{ json: { ...keywordSet, baseArticles } }];

// ── BrandFlow: Parse & Store Search Results ──────────────────────────────
// Maps the top 3 SerpAPI organic results directly into the article schema
// and persists them in n8n static data (survives between weekly executions).
// No AI generation — the search results ARE the articles.

const searchData = $input.first().json;
const organic = Array.isArray(searchData.organic_results)
  ? searchData.organic_results.slice(0, 3)
  : [];

if (organic.length === 0) {
  return [{ json: { success: true, newArticlesAdded: 0, totalStored: 0, articles: [],
    warning: 'No organic results returned by SerpAPI. Check SERPAPI_KEY and query.' } }];
}

// Pull context set by Build Search Query
const ctx = $('Build Search Query').first().json;
const { category, tags, baseArticles } = ctx;

// Load persisted articles from n8n static data
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.generatedArticles)) staticData.generatedArticles = [];

// Build deduplication set from all known slugs
const existingSlugs = new Set([
  ...staticData.generatedArticles.map(a => a.slug),
  ...(Array.isArray(baseArticles) ? baseArticles.map(a => a.slug) : [])
]);

// Determine next sequential article ID
const allIds = [...staticData.generatedArticles, ...(Array.isArray(baseArticles) ? baseArticles : [])]
  .map(a => parseInt((a.id || 'art-000').replace('art-', ''), 10))
  .filter(n => !isNaN(n));
let nextNum = allIds.length > 0 ? Math.max(...allIds) + 1 : 5;

const today = new Date().toISOString().split('T')[0];
const newArticles = [];

for (const result of organic) {
  const title = String(result.title || '').trim();
  const excerpt = String(result.snippet || '').trim().substring(0, 200);
  if (!title || !excerpt) continue;

  // Build URL-safe slug from title
  const slug = title
    .toLowerCase()
    .replace(/[^a-z0-9-]/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 80);

  // Skip duplicates
  if (existingSlugs.has(slug)) continue;
  existingSlugs.add(slug);

  // Conservatively estimate read time from snippet length
  const wordCount = excerpt.split(/\s+/).length;
  const readTime = `${Math.max(3, Math.ceil(wordCount * 10 / 200))} min read`;

  newArticles.push({
    id: 'art-' + String(nextNum).padStart(3, '0'),
    title,
    excerpt,
    category,
    readTime,
    publishedAt: today,
    slug,
    featured: false,
    tags
  });

  nextNum++;
}

// Prepend new articles so newest appear first
staticData.generatedArticles = [...newArticles, ...staticData.generatedArticles];

return [{ json: {
  success: true,
  newArticlesAdded: newArticles.length,
  totalStored: staticData.generatedArticles.length,
  articles: newArticles
}}];

// ── BrandFlow: Build Article Response ────────────────────────────────────
// Merges web-search-curated articles (stored in n8n static data across runs)
// with the baseline articles from the cPanel PHP endpoint.
// Deduplicates by slug, sorts newest-first, returns the combined feed.

const fetchResponse = $input.first().json;
const baseArticles = Array.isArray(fetchResponse.articles) ? fetchResponse.articles : [];

// Load all previously curated articles persisted in n8n
const staticData = $getWorkflowStaticData('global');
const storedArticles = Array.isArray(staticData.generatedArticles)
  ? staticData.generatedArticles
  : [];

// Merge: stored (newest curated) first, then base (static JSON from cPanel)
// Deduplicate by slug then by id
const seen = new Set();
const allArticles = [];

for (const article of [...storedArticles, ...baseArticles]) {
  const key = article.slug || article.id;
  if (key && !seen.has(key)) {
    seen.add(key);
    allArticles.push(article);
  }
}

// Sort newest publishedAt first
allArticles.sort((a, b) => {
  const da = new Date(a.publishedAt || 0).getTime();
  const db = new Date(b.publishedAt || 0).getTime();
  return db - da;
});

return [{
  json: {
    success: true,
    source: 'n8n-brandflow-insights',
    updatedAt: new Date().toISOString(),
    count: allArticles.length,
    articles: allArticles
  }
}];
